INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (103411, "", 870, 1034501039, "", "", "", 13, 1034501, "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (103411, 1, "わあ……素敵なケーキね！\nえ？　キミが作ったの？\nすごいじゃない！", 1034501040, 4, 1, "", 11, 1034501, 0, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "", "", 1034501041, "", "", "", 91, 1034501, "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("vo_adv_1034501", 0, "vo_adv_1034501_001", 1034501042, 0, "", "", 21, 1034501, "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (103411, 1, "麦しゅわに合わないかも……って、\nそんな気を使わなくていいわよ。\nだって、今日は飲むつもりはないもの。", 1034501043, 6, 1, "", 11, 1034501, 0, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "", "", 1034501044, "", "", "", 91, 1034501, "", "");
