INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (104611, 1, "にゃはは～！\n誕生日のお祝いしてくれて\nどうもありがとにゃ！", 1046501040, 6, 1, "", 11, 1046501, 0, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "", "", 1046501041, "", "", "", 91, 1046501, "", "");
