INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (105711, "", 870, 1057501039, "", "", "", 13, 1057501, "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (105711, 1, "お祝いしてくれてありがとう！\n私の誕生日、覚えててくれたんだね。\nすごくうれしいな。", 1057501040, 6, 1, "", 11, 1057501, 0, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "", "", 1057501041, "", "", "", 91, 1057501, "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES ("vo_adv_1057501", 0, "vo_adv_1057501_001", 1057501042, 0, "", "", 21, 1057501, "", "");
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (105711, 1, "このケーキ、すごく美味しそうだね。\n有名なお店のケーキなのかな？\nえ？　あなたが自分で作ってくれたの？\nすごーい！", 1057501043, 5, 1, "", 11, 1057501, 0, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "", "", 1057501044, "", "", "", 91, 1057501, "", "");
