INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (105711, 1, "なんだかやる気が出てきちゃった！\nもしよかったら、このあと一緒に\n依頼を受けにいこうよ！", 1057501046, 7, 1, "", 11, 1057501, 0, 0);
INSERT INTO `v1_d97acaf916ac539990b252ce2a0360b31cc96b735f42d0f1b66b4ccebf906ba2` VALUES (0, "", "", 1057501047, "", "", "", 91, 1057501, "", "");
